export const TOTAL_STATE_PROGRAMS = STATE_PROGRAMS.length;
export const TOTAL_REGIONAL_COUPONS = REGIONAL_COUPONS.length;

// Helper: get programs for a given state code (includes Federal programs always)
export function getProgramsForState(stateCode: string): StateProgram[] {
  const code = stateCode.toUpperCase();
  return STATE_PROGRAMS.filter(p => p.state === "Federal" || p.state === code || p.state === "Local");
}

// Helper: get regional coupons for a given state code
export function getCouponsForState(stateCode: string): StateProgram[] {
  const code = stateCode.toUpperCase();
  return REGIONAL_COUPONS.filter(p => p.state === "Federal" || p.state === code || p.state === "Local");
}
